func researchEvidenceTypeLabel(value string) string {
	switch strings.ToLower(strings.TrimSpace(value)) {
	case "service":
		return "Service"
	case "pension":
		return "Pension"
	case "burial":
		return "Burial"
	case "vital":
		return "Vital"
	case "family":
		return "Family"
	case "archive":
		return "Local Archive"
	default:
		return "General"
	}
}

func researchTaskStatusLabel(value string) string {
	if strings.EqualFold(strings.TrimSpace(value), "resolved") {
		return "Resolved"
	}
	return "Open"
}

func researchTaskStatusClass(value string) string {
	if strings.EqualFold(strings.TrimSpace(value), "resolved") {
		return "rounded-full border border-slate-200 bg-slate-100 px-3 py-1 text-xs font-semibold uppercase tracking-[0.18em] text-slate-600"
	}
	return "rounded-full border border-[rgba(111,44,38,0.35)] bg-[rgba(111,44,38,0.08)] px-3 py-1 text-xs font-semibold uppercase tracking-[0.18em] text-[#6f2c26]"
}

